// DrawerMenu.js
import React from 'react';
import Drawer from '@material-ui/core/Drawer';
import IconButton from '@material-ui/core/IconButton';
import MenuIcon from '@material-ui/icons/Menu';
import AuthenticatedMenu from './AuthenticatedMenu';
import UnauthenticatedMenu from './UnauthenticatedMenu';
import { makeStyles } from '@material-ui/core';

const useStyles = makeStyles((theme) => ({
  mainMenuContainer: {
    display: 'flex',
    flexDirection: 'column',
    height: '100%',
  },
  mainMenuItem: {
    fontSize: '1rem',
    paddingTop: 1,
    paddingBottom: 1,
  },
  subMenuItem: {
    fontSize: '0.2rem',
    paddingTop: 1,
    paddingBottom: 1,
    paddingLeft: theme.spacing(3),
  },
}));

const DrawerMenu = ({ categories, isAuthenticated }) => {
  const classes = useStyles();
  const [isDrawerOpen, setIsDrawerOpen] = React.useState(false);

  const handleDrawerOpen = () => {
    setIsDrawerOpen(true);
  };

  const handleDrawerClose = () => {
    setIsDrawerOpen(false);
  };

  return (
    <div>
      <IconButton
        edge="start"
        color="inherit"
        aria-label="menu"
        onClick={handleDrawerOpen}
      >
        <MenuIcon />
      </IconButton>
      <Drawer anchor="top" open={isDrawerOpen} onClose={handleDrawerClose}>
        <div className={classes.mainMenuContainer}>
        <List component="nav" aria-label="main mailbox folders">
      {categories.map((category) => (
        <div key={category._id}>
          <ListItem className={classes.menuItem}>
            <ListItemText primary={category.mainMenu} />
            <div>
              <IconButton>
                <AddIcon />
              </IconButton>
              <IconButton>
                <DeleteIcon />
              </IconButton>
            </div>
          </ListItem>
          <List component="div" disablePadding>
            {category.subMenu.map((subItem, index) => (
              <ListItem key={`${category._id}-${index}`} className={classes.subMenuItem}>
                <ListItemText primary={subItem} />
              </ListItem>
            ))}
          </List>
        </div>
      ))}
    </List>
        </div>
      </Drawer>
    </div>
  );
};

export default DrawerMenu;
